13: @extHostNamedCustomer(MainContext.MainThreadDiagnostics)
14: export class MainThreadDiagnostics implements MainThreadDiagnosticsShape {
15: 
16: 	private readonly _activeOwners = new Set<string>();
17: 
18: 	private readonly _proxy: ExtHostDiagnosticsShape;
19: 	private readonly _markerListener: IDisposable;
20: 
21: 	constructor(
22: 		extHostContext: IExtHostContext,
23: 		@IMarkerService private readonly _markerService: IMarkerService,
24: 		@IUriIdentityService private readonly _uriIdentService: IUriIdentityService,
25: 	) {
26: 		this._proxy = extHostContext.getProxy(ExtHostContext.ExtHostDiagnostics);
27: 
28: 		this._markerListener = this._markerService.onMarkerChanged(this._forwardMarkers, this);
29: 	}
30: 
31: 	dispose(): void {
32: 		this._markerListener.dispose();
33: 		this._activeOwners.forEach(owner => this._markerService.changeAll(owner, []));
34: 		this._activeOwners.clear();
35: 	}
36: 
37: 	private _forwardMarkers(resources: readonly URI[]): void {
38: 		const data: [UriComponents, IMarkerData[]][] = [];
39: 		for (const resource of resources) {
40: 			const allMarkerData = this._markerService.read({ resource });
41: 			if (allMarkerData.length === 0) {
42: 				data.push([resource, []]);
43: 			} else {
44: 				const forgeinMarkerData = allMarkerData.filter(marker => !this._activeOwners.has(marker.owner));
45: 				if (forgeinMarkerData.length > 0) {
46: 					data.push([resource, forgeinMarkerData]);
47: 				}
48: 			}
49: 		}
50: 		if (data.length > 0) {
51: 			this._proxy.$acceptMarkersChange(data);
52: 		}
53: 	}
54: 
55: 	$changeMany(owner: string, entries: [UriComponents, IMarkerData[]][]): void {
56: 		for (const entry of entries) {
57: 			const [uri, markers] = entry;
58: 			if (markers) {
59: 				for (const marker of markers) {
60: 					if (marker.relatedInformation) {
61: 						for (const relatedInformation of marker.relatedInformation) {
62: 							relatedInformation.resource = URI.revive(relatedInformation.resource);
63: 						}
64: 					}
65: 					if (marker.code && typeof marker.code !== 'string') {
66: 						marker.code.target = URI.revive(marker.code.target);
67: 					}
68: 				}
69: 			}
70: 			this._markerService.changeOne(owner, this._uriIdentService.asCanonicalUri(URI.revive(uri)), markers);
71: 		}
72: 		this._activeOwners.add(owner);
73: 	}
74: 
75: 	$clear(owner: string): void {
76: 		this._markerService.changeAll(owner, []);
77: 		this._activeOwners.delete(owner);
78: 	}
79: }
