		if (Math.random() * 1000 <= 1 || configuration.enableDiagnosticsTelemetry) {
			this._diagnosticsTelemetryManager = this._register(new DiagnosticsTelemetryManager(telemetryReporter, this._currentDiagnostics));
		}

		// Watch for file system changes to detect stale diagnostics after Git branch switches
		this._fileSystemWatcher = this._register(
			vscode.workspace.createFileSystemWatcher('**/*.{ts,tsx,js,jsx}', false, false, false)
		);

		// Clear diagnostics when files change on disk (e.g., from Git operations)
		this._register(this._fileSystemWatcher.onDidChange(uri => {
			this.clearDiagnosticsForFile(uri);
		}));

		// Clear diagnostics when files are deleted on disk
		this._register(this._fileSystemWatcher.onDidDelete(uri => {
			this.deleteAllDiagnosticsInFile(uri);
		}));
	}

	public override dispose() {
		super.dispose();

		for (const value of this._pendingUpdates.values()) {
			clearTimeout(value);
		}
		this._pendingUpdates.clear();
	}

	public reInitialize(): void {
		this._currentDiagnostics.clear();
		this._diagnostics.clear();
	}

	public setValidate(language: DiagnosticLanguage, value: boolean) {
		const didUpdate = this._settings.setValidate(language, value);
		if (didUpdate) {
			this.rebuildAll();
		}
	}

	public setEnableSuggestions(language: DiagnosticLanguage, value: boolean) {
		const didUpdate = this._settings.setEnableSuggestions(language, value);
		if (didUpdate) {
			this.rebuildAll();
		}
	}

	public updateDiagnostics(
		file: vscode.Uri,
		language: DiagnosticLanguage,
		kind: DiagnosticKind,
		diagnostics: ReadonlyArray<vscode.Diagnostic>,
		ranges: ReadonlyArray<vscode.Range> | undefined,
	): void {
		let didUpdate = false;
		const entry = this._diagnostics.get(file);
		if (entry) {
			didUpdate = entry.updateDiagnostics(language, kind, diagnostics, ranges);
		} else if (diagnostics.length) {
